# Sort by length of en_bytes descending (longest first) so longer patterns are tried first
PAIRS.sort(key=lambda p: -len(p[0]))


def translate_file(path):
    with open(path, 'rb') as f:
        raw = f.read()
    original = raw
    n_replaced = 0
    for en, zh in PAIRS:
        if en in raw:
            n = raw.count(en)
            raw = raw.replace(en, zh)
            n_replaced += n
    if raw != original:
        with open(path, 'wb') as f:
            f.write(raw)
    return n_replaced


def main():
    targets = [
        'tokio/index.html',
        'tokio/attr.main.html',
        'tokio/attr.test.html',
        'tokio/macro.join.html',
        'tokio/macro.select.html',
        'tokio/macro.try_join.html',
        'tokio/macro.pin.html',
        'tokio/macro.task_local.html',
        'tokio/macro.join!.html',
        'tokio/macro.pin!.html',
        'tokio/all.html',
    ]
    total = 0
    for t in targets:
        n = translate_file(t)
        if n > 0:
            print(f'  {t}: {n} replacements')
            total += n
    print(f'\nTotal: {total} replacements')


if __name__ == '__main__':
    main()
